import * as argon2 from '@node-rs/argon2';
import { randomInt } from 'crypto';
import { query, queryOne } from '../database.js';
import { AUTH, ARGON2 } from '../constants.js';

// Minimal interface for a transaction client — satisfied by pg.PoolClient
type TxClient = { query: (text: string, params?: unknown[]) => Promise<unknown> };

export function generatePin(): string {
  return String(randomInt(100000, 999999));
}

async function hashPin(pin: string): Promise<string> {
  return argon2.hash(pin, {
    memoryCost: ARGON2.MEMORY_COST,
    timeCost: ARGON2.TIME_COST,
    parallelism: ARGON2.PARALLELISM,
  });
}

async function comparePin(pin: string, hash: string): Promise<boolean> {
  return argon2.verify(hash, pin);
}

export async function createPin(
  email: string,
  purpose: 'login' | 'verification',
  client?: TxClient,
  plainPin?: string,
): Promise<string> {
  const pin = plainPin ?? generatePin();
  const pinHash = await hashPin(pin);
  const expiresAt = new Date(Date.now() + AUTH.PIN_TTL_MS);

  const exec = (text: string, params?: unknown[]) =>
    client ? client.query(text, params) : query(text, params);

  // Invalidate any existing unused PINs for this email/purpose
  await exec(
    `UPDATE auth_pins SET used_at = NOW() WHERE email = $1 AND purpose = $2 AND used_at IS NULL`,
    [email, purpose],
  );

  await exec(
    `INSERT INTO auth_pins (email, pin_hash, purpose, expires_at) VALUES ($1, $2, $3, $4)`,
    [email, pinHash, purpose, expiresAt.toISOString()],
  );

  return pin;
}

export async function verifyPin(
  email: string,
  pin: string,
  purpose: 'login' | 'verification',
): Promise<boolean> {
  const record = await queryOne<{ id: string; attempts: number; pin_hash: string }>(
    `SELECT id, attempts, pin_hash FROM auth_pins
     WHERE email = $1 AND purpose = $2 AND used_at IS NULL AND expires_at > NOW()
     ORDER BY created_at DESC LIMIT 1`,
    [email, purpose],
  );

  if (!record) return false;

  // Rate limit: max attempts
  if (record.attempts >= AUTH.PIN_MAX_ATTEMPTS) return false;

  // Increment attempts
  await query('UPDATE auth_pins SET attempts = attempts + 1 WHERE id = $1', [record.id]);

  const valid = await comparePin(pin, record.pin_hash);

  if (valid) {
    // Mark as used
    await query('UPDATE auth_pins SET used_at = NOW() WHERE id = $1', [record.id]);
    return true;
  }

  return false;
}

export const AUTH = {
  PIN_LENGTH: 6,
  PIN_TTL_MS: 5 * 60 * 1000,          // 5 minutes
  PIN_MAX_ATTEMPTS: 5,
  INVITATION_TTL_MS: 7 * 24 * 60 * 60 * 1000,  // 7 days
  JWT_EXPIRY: '7d',
  CHALLENGE_TTL_MS: 5 * 60 * 1000,  // 5 minutes
} as const;

export const ARGON2 = {
  MEMORY_COST: 19456, // 19 MiB — OWASP minimum
  TIME_COST: 2,
  PARALLELISM: 1,
} as const;

export const RATE_LIMITS = {
  REGISTER:              { max: 5,  timeWindow: '1 minute'  },
  LOGIN:                 { max: 5,  timeWindow: '1 minute'  },
  VERIFY_PIN:            { max: 10, timeWindow: '1 minute'  },
  REFRESH:               { max: 10, timeWindow: '1 minute'  },
  INVITATIONS:           { max: 20, timeWindow: '1 hour'    },
  PASSKEY_DELETE:        { max: 10, timeWindow: '1 hour'    },
  PASSKEY_LOGIN_BEGIN:   { max: 10, timeWindow: '5 minutes' },
  PASSKEY_LOGIN_COMPLETE: { max: 10, timeWindow: '5 minutes' },
  PASSKEY_REGISTER:      { max: 5,  timeWindow: '5 minutes' },
  USER_UPDATE:           { max: 20, timeWindow: '1 minute'  },
  ORG_CREATE:            { max: 5,  timeWindow: '1 hour'    },
  ORG_UPDATE:            { max: 20, timeWindow: '1 minute'  },
  AI_CHAT:               { max: 20, timeWindow: '1 minute'  },
} as const;

export const SETTINGS = {
  MAX_SIZE_BYTES: 10_000,
  BODY_LIMIT_BYTES: 100 * 1024, // 100 KB — prevents memory amplification attacks
} as const;

export const AI = {
  MAX_MESSAGE_LENGTH: 4000,
  MAX_HISTORY_MESSAGES: 50,
} as const;

